mapper.select:
SELECT kb.id, kb.user_id, u.username, kb.name, kb.description, kb.document_url, kb.chunk_ids, kb.chunk_count, kb.status, kb.deleted, kb.create_time, kb.update_time FROM knowledge_base kb LEFT JOIN sys_user u ON kb.user_id = u.id WHERE kb.deleted = 0
AND kb.user_id = #{userId}
ORDER BY kb.create_time DESC
